    def _hash_secret(self, secret: str) -> str:
        return hashlib.sha256(secret.encode()).hexdigest()
    
    def _validate_redirect_uri(self, client_id: str, redirect_uri: str) -> bool:
        if client_id not in self.clients:
            return False
        
        registered_uri = self.clients[client_id]['redirect_uri']
        
        parsed_redirect = urlparse(redirect_uri)
        parsed_registered = urlparse(registered_uri)
        
        if not parsed_redirect.scheme or not parsed_redirect.netloc:
            return False
        
        if parsed_redirect.scheme != parsed_registered.scheme:
            return False
        
        if not redirect_uri.startswith(registered_uri):
            return False
        
        if len(redirect_uri) > len(registered_uri):
            next_char = redirect_uri[len(registered_uri)]
            if next_char not in ['/', '?', '#', ':', '.']:
                return False
        
        redirect_host = parsed_redirect.netloc.split(':')[0].lower()
        registered_host = parsed_registered.netloc.split(':')[0].lower()
        
        if not self._is_valid_host_match(redirect_host, registered_host):
            return False
        
        return True
    
    def _is_valid_host_match(self, redirect_host: str, registered_host: str) -> bool:
        if redirect_host == registered_host:
            return True
        
        if redirect_host.endswith('.' + registered_host):
            subdomain = redirect_host[:-len(registered_host)-1]
            if re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?$', subdomain):
                return True
        
        return False
    
